19	import { useMounted } from '@mantine/hooks';
20	import { notifications } from '@mantine/notifications';
21	import { IconAlertTriangle, IconCheck } from '@tabler/icons-react';
22	import { zod4Resolver } from 'mantine-form-zod-resolver';
23	import { PlayerResponse } from 'prisma/generated/enums';
24	import { useState } from 'react';
25	import z from 'zod';
26	
27	import { config } from '@/lib/config';
28	import { captureUnexpectedError } from '@/lib/observability/sentry';
29	import {
30	    InvitationResponseInputSchema,
31	    SubmitGameInvitationResponseProxy,
32	} from '@/types/actions/SubmitGameInvitationResponse';
33	import { GameInvitationResponseDetails } from '@/types/GameInvitationResponseDetails';
34	
35	const formSchema = InvitationResponseInputSchema.omit({ token: true }).extend({
36	    comment: z.string().max(127).optional(),
37	});
38	type FormValues = z.infer<typeof formSchema>;
39	
40	const responseOptions = [
41	    { value: PlayerResponse.Yes, label: 'Yes' },
42	    { value: PlayerResponse.No, label: 'No' },
43	    { value: PlayerResponse.Dunno, label: 'Dunno' },
44	];
45	
46	/**
47	 * Responses that players can select themselves in this form.
48	 */
49	const playerEditableResponses = new Set<PlayerResponse>([
50	    PlayerResponse.Yes,
51	    PlayerResponse.No,
52	    PlayerResponse.Dunno,
53	]);
54	
55	/**
56	 * Returns the initial response value used by the editable select input.
57	 *
58	 * Player invitations can carry admin-only response values (for example
59	 * `Excused`) that should still be displayed in the summary, but players can
60	 * only submit Yes/No/Dunno from this form.
61	 *
62	 * @param response - Incoming invitation response from query details.
63	 * @returns The player-editable response value for the form select.
64	 */
65	function getInitialPlayerResponse(responseInput: GameInvitationResponseDetails['response']) {
66	    const response = responseInput &&
67	        playerEditableResponses.has(responseInput) ? responseInput : PlayerResponse.Yes;
68	
69	    return response;
70	}
71	
72	interface Props {
73	    details: GameInvitationResponseDetails;
74	    onSubmitGameInvitationResponse: SubmitGameInvitationResponseProxy;
75	}
76	
77	export const GameInvitationResponseForm = ({
78	    details,
79	    onSubmitGameInvitationResponse,
80	}: Props) => {
81	    const mounted = useMounted();
82	    const response = getInitialPlayerResponse(details.response);
83	    const [currentResponse, setCurrentResponse] = useState(details.response);
84	    const [currentComment, setCurrentComment] = useState(details.comment);
85	    const [canSubmitWithoutChanges, setCanSubmitWithoutChanges] = useState(!details.response);
86	
87	    const form = useForm<FormValues>({
88	        initialValues: {
89	            response,
90	            goalie: details.goalie ?? false,
91	            comment: details.comment ?? '',
92	        },
93	        validate: zod4Resolver(formSchema),
94	        validateInputOnBlur: true,
95	    });
96	
97	    /**
98	     * The form is dirty if the user has changed a field, or if there is no
99	     * saved response yet. In that case, submission is allowed without
100	     * interaction so users can quickly confirm the default Yes value. Once a
101	     * response has been saved, the button should disable again until the form
102	     * changes.
103	     */
104	    const isFormDirty = form.isDirty() || canSubmitWithoutChanges;
105	
106	    const handleSubmit = async (values: FormValues) => {
107	        const id = notifications.show({
108	            loading: true,
109	            title: 'Saving response',
110	            message: 'Saving your response...',
111	            autoClose: false,
112	            withCloseButton: false,
113	        });
114	
115	        try {
116	            await onSubmitGameInvitationResponse({
117	                token: details.token,
118	                response: values.response,
119	                goalie: values.goalie,
120	                comment: values.comment?.trim() ?? null,
121	            });
122	
123	            setCurrentResponse(values.response);
124	            setCurrentComment(values.comment?.trim() ?? '');
125	            setCanSubmitWithoutChanges(false);
126	
127	            notifications.update({
128	                id,
129	                color: 'teal',
130	                title: 'Response saved',
131	                message: 'Your response has been updated.',
132	                icon: <IconCheck size={config.notificationIconSize} />,
133	                loading: false,
134	                autoClose: config.notificationAutoClose,
135	            });
136	        } catch (error) {
137	            captureUnexpectedError(error, {
138	                layer: 'client',
139	                component: 'GameInvitationResponseForm',
140	                action: 'submitResponse',
141	                route: '/footy/game/[id]',
142	                extra: {
143	                    playerId: details.playerId,
144	                    gameDayId: details.gameDayId,
145	                    response: values.response,
146	                },
147	            });
148	            const message = error instanceof Error ? error.message : 'Failed to save response';
149	            notifications.update({
150	                id,
151	                color: 'red',
152	                title: 'Error',
153	                message,
154	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
155	                loading: false,
156	                autoClose: false,
157	                withCloseButton: true,
158	            });
159	        }
160	    };
161	
162	    const responseColor = {
163	        [PlayerResponse.Yes.toString()]: 'green',
164	        [PlayerResponse.No.toString()]: 'red',
165	        [PlayerResponse.Dunno.toString()]: 'grey',
166	    } as const;
167	    const displayResponse = currentResponse ? (
168	        <Badge color={responseColor[currentResponse.toString()]} variant="filled" size="sm">
169	            {currentResponse}
170	        </Badge>
171	    ) : (
172	        <Badge color="grey" variant="filled" size="sm">
173	            No response yet
174	        </Badge>
175	    );
176	    const displayComment = currentComment ? `("${currentComment}")` : '';
177	    const playerLink = details.playerLogin ? `/footy/player/${details.playerLogin}` : `/footy/player/${details.playerId}`;
178	
179	    return (
180	        <Box component="form" onSubmit={form.onSubmit(handleSubmit)}>
181	            <Stack gap="md">
182	                <Title order={2} mb="xs" w="100%" ta="center">
183	                    {currentResponse ? 'Thanks for Your Response' : 'Enter Your Response'}
184	                </Title>
185	                <Divider mb="xs" />
186	                <Flex align="center" gap="md" wrap="wrap">
187	                    <Avatar
188	                        src={`/api/footy/player/${details.playerId}/mugshot`}
189	                        alt={details.playerName}
190	                        size={48}
191	                        radius="xl"
192	                    />
193	                    <Anchor href={playerLink}>{details.playerName}</Anchor>: {displayResponse} {displayComment}
194	                </Flex>
195	                <Select
196	                    label="Response"
197	                    data={responseOptions}
198	                    value={form.values.response}
199	                    /* v8 ignore next -- allowDeselect={false} means value is never null */
200	                    onChange={(value) => form.setFieldValue('response', (value ?? PlayerResponse.Yes))}
201	                    allowDeselect={false}
202	                />
203	                <Checkbox
204	                    label="Goalie"
205	                    {...form.getInputProps('goalie', { type: 'checkbox' })}
206	                />
207	                <TextInput
208	                    label="Optional comment/excuse"
209	                    maxLength={127}
210	                    {...form.getInputProps('comment')}
211	                />
212	                <Button type="submit" w="fit-content" loading={!mounted} disabled={!isFormDirty}>
213	                    Save Response
214	                </Button>
215	                <Text mt="xl">
216	                    You can change it later if you need to, even if the teams have been picked - either by clicking
217	                    on the link in the email you received, or by logging in to the site at{' '}
218	                    <Anchor href={`/footy/game/${details.gameDayId}`}>the game page</Anchor>. If you can&apos;t get to
219	                    a computer, message Jon on <strong>{config.organiserPhoneNumber}</strong>.
220	                </Text>
221	            </Stack>
222	        </Box>
223	    );
224	};
